// T613 GigAcceptanceLockGateway — 3-guard gate
const GIG_ACCEPT_LOCK_PREFIX = 'gig-accept-lock' as const;

async acceptGig(gigId: string, bidId: string): Promise<DataProcessResult<Record<string, unknown>>> {
  const tenantId = this.tenantContext.getTenantId(); // ALS only — never from payload

  // ORDER 1: BOLA — verify requesting tenant owns the gig
  const gigResult = await this.db.searchDocuments('gigs', { gigId });
  if (!gigResult.data?.length) return DataProcessResult.failure('GIG_NOT_FOUND', ...);
  const gig = gigResult.data[0];
  if (gig['clientTenantId'] !== tenantId) {
    await this.queue.enqueue('GigAcceptanceFailed', { gigId, bidId, tenantId, failureCode: 'BOLA_VIOLATION' });
    return DataProcessResult.failure('BOLA_VIOLATION', 'Tenant does not own this gig');
  }

  // ORDER 2: SETNX — prevent concurrent double-acceptance
  const lockKey = `${GIG_ACCEPT_LOCK_PREFIX}:${gigId}`;
  const existing = await this.db.searchDocuments('gig-locks', { lockKey });
  if (existing.data?.length) return DataProcessResult.success({ alreadyAccepted: true });
  await this.db.storeDocument('gig-locks', { lockKey, gigId, createdAt: new Date().toISOString() });

  // ORDER 3: OCC bid status
  const bidResult = await this.db.searchDocuments('bids', { bidId });
  if (!bidResult.data?.length) { /* emit GigAcceptanceFailed BID_NOT_FOUND */ }
  if (bidResult.data[0]['status'] !== 'OPEN') { /* emit GigAcceptanceFailed BID_NOT_OPEN */ }

  // DNA-8: audit BEFORE enqueue
  await this.db.storeDocument('gig-audit', { gigId, bidId, tenantId, action: 'GIG_ACCEPTED' });
  await this.queue.enqueue('GigAccepted', { gigId, bidId, tenantId });
  return DataProcessResult.success({ gigId, bidId });
}
